import { createZapierApi } from "../../api";
import { resolveCredentials } from "../../credentials";
import { ZAPIER_BASE_URL, ZAPIER_MAX_NETWORK_RETRIES, ZAPIER_MAX_NETWORK_RETRY_DELAY_MS, } from "../../constants";
// API plugin requires no context and provides api in context
export const apiPlugin = (params) => {
    // Extract all options - everything passed to the plugin
    const { fetch: customFetch = globalThis.fetch, baseUrl = ZAPIER_BASE_URL, credentials, token, onEvent, debug = false, maxNetworkRetries = ZAPIER_MAX_NETWORK_RETRIES, maxNetworkRetryDelayMs = ZAPIER_MAX_NETWORK_RETRY_DELAY_MS, } = params.context.options;
    // Create the API client - it will handle token resolution internally
    const api = createZapierApi({
        baseUrl,
        credentials,
        token,
        debug,
        fetch: customFetch,
        onEvent,
        maxNetworkRetries,
        maxNetworkRetryDelayMs,
    });
    // Return flat structure with context only
    return {
        context: {
            api, // Provide API client in context for other plugins to use
            resolveCredentials: () => resolveCredentials({
                credentials,
                token,
                baseUrl,
            }),
        },
    };
};
